353: absl::optional<Grpc::Status::GrpcStatus>
354: FaultFilter::abortGrpcStatus(const Http::RequestHeaderMap& request_headers) {
355:   auto grpc_status = fault_settings_->requestAbort()->grpcStatusCode(&request_headers);
356:   if (!grpc_status.has_value()) {
357:     return absl::nullopt;
358:   }
359: 
360:   auto default_grpc_status_code = static_cast<uint64_t>(grpc_status.value());
361:   auto runtime_grpc_status_code = config_->runtime().snapshot().getInteger(
362:       fault_settings_->abortGrpcStatusRuntime(), default_grpc_status_code);
363: 
364:   if (!downstream_cluster_abort_grpc_status_key_.empty()) {
365:     runtime_grpc_status_code = config_->runtime().snapshot().getInteger(
366:         downstream_cluster_abort_grpc_status_key_, default_grpc_status_code);
367:   }
368: 
369:   return static_cast<Grpc::Status::GrpcStatus>(runtime_grpc_status_code);
370: }
