64: FilterConfig::FilterConfig(const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& config,
65:                            Stats::Scope& scope, const std::string& stats_prefix,
66:                            Server::Configuration::ServerFactoryContext& factory_context)
67:     : allow_partial_message_(config.with_request_body().allow_partial_message()),
68:       failure_mode_allow_(config.failure_mode_allow()),
69:       failure_mode_allow_header_add_(config.failure_mode_allow_header_add()),
70:       clear_route_cache_(config.clear_route_cache()),
71:       max_request_bytes_(config.with_request_body().max_request_bytes()),
72: 
73:       // `pack_as_bytes_` should be true when configured with the HTTP service because there is no
74:       // difference to where the body is written in http requests, and a value of false here will
75:       // cause non UTF-8 body content to be changed when it doesn't need to.
76:       pack_as_bytes_(config.has_http_service() || config.with_request_body().pack_as_bytes()),
77: 
78:       encode_raw_headers_(config.encode_raw_headers()),
79: 
80:       status_on_error_(toErrorCode(config.status_on_error().code())),
81:       validate_mutations_(config.validate_mutations()), scope_(scope),
82:       decoder_header_mutation_checker_(
83:           config.has_decoder_header_mutation_rules()
84:               ? absl::optional<Filters::Common::MutationRules::Checker>(
85:                     Filters::Common::MutationRules::Checker(config.decoder_header_mutation_rules(),
86:                                                             factory_context.regexEngine()))
87:               : absl::nullopt),
88:       enable_dynamic_metadata_ingestion_(
89:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, enable_dynamic_metadata_ingestion, true)),
90:       runtime_(factory_context.runtime()), http_context_(factory_context.httpContext()),
91:       filter_metadata_(config.has_filter_metadata() ? absl::optional(config.filter_metadata())
92:                                                     : absl::nullopt),
93:       emit_filter_state_stats_(config.emit_filter_state_stats()),
94:       filter_enabled_(config.has_filter_enabled()
95:                           ? absl::optional<Runtime::FractionalPercent>(
96:                                 Runtime::FractionalPercent(config.filter_enabled(), runtime_))
97:                           : absl::nullopt),
98:       filter_enabled_metadata_(
99:           config.has_filter_enabled_metadata()
100:               ? absl::optional<Matchers::MetadataMatcher>(
101:                     Matchers::MetadataMatcher(config.filter_enabled_metadata(), factory_context))
102:               : absl::nullopt),
103:       deny_at_disable_(config.has_deny_at_disable()
104:                            ? absl::optional<Runtime::FeatureFlag>(
105:                                  Runtime::FeatureFlag(config.deny_at_disable(), runtime_))
106:                            : absl::nullopt),
107:       pool_(scope_.symbolTable()),
108:       metadata_context_namespaces_(config.metadata_context_namespaces().begin(),
109:                                    config.metadata_context_namespaces().end()),
110:       typed_metadata_context_namespaces_(config.typed_metadata_context_namespaces().begin(),
111:                                          config.typed_metadata_context_namespaces().end()),
112:       route_metadata_context_namespaces_(config.route_metadata_context_namespaces().begin(),
113:                                          config.route_metadata_context_namespaces().end()),
114:       route_typed_metadata_context_namespaces_(
115:           config.route_typed_metadata_context_namespaces().begin(),
116:           config.route_typed_metadata_context_namespaces().end()),
117:       include_peer_certificate_(config.include_peer_certificate()),
118:       include_tls_session_(config.include_tls_session()),
119:       charge_cluster_response_stats_(
120:           PROTOBUF_GET_WRAPPED_OR_DEFAULT(config, charge_cluster_response_stats, true)),
121:       stats_(generateStats(stats_prefix, config.stat_prefix(), scope)),
122:       ext_authz_ok_(pool_.add(createPoolStatName(config.stat_prefix(), "ok"))),
123:       ext_authz_denied_(pool_.add(createPoolStatName(config.stat_prefix(), "denied"))),
124:       ext_authz_error_(pool_.add(createPoolStatName(config.stat_prefix(), "error"))),
125:       ext_authz_invalid_(pool_.add(createPoolStatName(config.stat_prefix(), "invalid"))),
126:       ext_authz_failure_mode_allowed_(
127:           pool_.add(createPoolStatName(config.stat_prefix(), "failure_mode_allowed"))) {
128:   auto bootstrap = factory_context.bootstrap();
129:   auto labels_key_it =
130:       bootstrap.node().metadata().fields().find(config.bootstrap_metadata_labels_key());
131:   if (labels_key_it != bootstrap.node().metadata().fields().end()) {
132:     for (const auto& labels_it : labels_key_it->second.struct_value().fields()) {
133:       destination_labels_[labels_it.first] = labels_it.second.string_value();
134:     }
135:   }
136: 
137:   if (config.has_allowed_headers() &&
138:       config.http_service().authorization_request().has_allowed_headers()) {
139:     throw EnvoyException("Invalid duplicate configuration for allowed_headers.");
140:   }
141: 
142:   // An unset request_headers_matchers_ means that all client request headers are allowed through
143:   // to the authz server; this is to preserve backwards compatibility when introducing
144:   // allowlisting of request headers for gRPC authz servers. Pre-existing support is for
145:   // HTTP authz servers only and defaults to blocking all but a few headers (i.e. Authorization,
146:   // Method, Path and Host).
147:   if (config.has_grpc_service() && config.has_allowed_headers()) {
148:     allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
149:         config.allowed_headers(), false, factory_context);
150:   } else if (config.has_http_service()) {
151:     if (config.http_service().authorization_request().has_allowed_headers()) {
152:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
153:           config.http_service().authorization_request().allowed_headers(), true, factory_context);
154:     } else {
155:       allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
156:           config.allowed_headers(), true, factory_context);
157:     }
158:   }
159:   if (config.has_disallowed_headers()) {
160:     disallowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
161:         config.disallowed_headers(), false, factory_context);
162:   }
