165: void FilterConfigPerRoute::merge(const FilterConfigPerRoute& other) {
166:   // We only merge context extensions here, and leave boolean flags untouched since those flags are
167:   // not used from the merged config.
168:   auto begin_it = other.context_extensions_.begin();
169:   auto end_it = other.context_extensions_.end();
170:   for (auto it = begin_it; it != end_it; ++it) {
171:     context_extensions_[it->first] = it->second;
172:   }
