311: Http::FilterDataStatus Filter::decodeData(Buffer::Instance& data, bool end_stream) {
312:   if (buffer_data_ && !skip_check_) {
313:     const bool buffer_is_full = isBufferFull(data.length());
314:     if (end_stream || buffer_is_full) {
315:       ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request since {}",
316:                        *decoder_callbacks_, buffer_is_full ? "buffer is full" : "stream is ended");
317:       // Make sure data is available in initiateCall.
318:       decoder_callbacks_->addDecodedData(data, true);
319:       initiateCall(*request_headers_);
320:       return filter_return_ == FilterReturn::StopDecoding
321:                  ? Http::FilterDataStatus::StopIterationAndWatermark
322:                  : Http::FilterDataStatus::Continue;
323:     } else {
324:       return Http::FilterDataStatus::StopIterationAndBuffer;
325:     }
326:   }
327: 
328:   return Http::FilterDataStatus::Continue;
329: }
