331: Http::FilterTrailersStatus Filter::decodeTrailers(Http::RequestTrailerMap&) {
332:   if (buffer_data_ && !skip_check_) {
333:     if (filter_return_ != FilterReturn::StopDecoding) {
334:       ENVOY_STREAM_LOG(debug, "ext_authz filter finished buffering the request",
335:                        *decoder_callbacks_);
336:       initiateCall(*request_headers_);
337:     }
338:     return filter_return_ == FilterReturn::StopDecoding ? Http::FilterTrailersStatus::StopIteration
339:                                                         : Http::FilterTrailersStatus::Continue;
340:   }
341: 
342:   return Http::FilterTrailersStatus::Continue;
343: }
