470: void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
471:   state_ = State::Complete;
472:   using Filters::Common::ExtAuthz::CheckStatus;
473:   Stats::StatName empty_stat_name;
474: 
475:   updateLoggingInfo();
476: 
477:   if (!response->dynamic_metadata.fields().empty()) {
478:     if (!config_->enableDynamicMetadataIngestion()) {
479:       ENVOY_STREAM_LOG(trace,
480:                        "Response is trying to inject dynamic metadata, but dynamic metadata "
481:                        "ingestion is disabled. Ignoring...",
482:                        *decoder_callbacks_);
483:       stats_.ignored_dynamic_metadata_.inc();
484:     } else {
485:       // Add duration of call to dynamic metadata if applicable
486:       if (start_time_.has_value() && response->status == CheckStatus::OK) {
487:         ProtobufWkt::Value ext_authz_duration_value;
488:         auto duration =
489:             decoder_callbacks_->dispatcher().timeSource().monotonicTime() - start_time_.value();
490:         ext_authz_duration_value.set_number_value(
491:             std::chrono::duration_cast<std::chrono::milliseconds>(duration).count());
492:         (*response->dynamic_metadata.mutable_fields())["ext_authz_duration"] =
493:             ext_authz_duration_value;
494:       }
495:       decoder_callbacks_->streamInfo().setDynamicMetadata("envoy.filters.http.ext_authz",
496:                                                           response->dynamic_metadata);
497:     }
498:   }
499: 
500:   switch (response->status) {
501:   case CheckStatus::OK: {
502:     // Any changes to request headers or query parameters can affect how the request is going to be
503:     // routed. If we are changing the headers we also need to clear the route
504:     // cache.
505:     if (config_->clearRouteCache() &&
506:         (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
507:          !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
508:          !response->query_parameters_to_remove.empty())) {
509:       ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
510:       decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
511:     }
512: 
513:     ENVOY_STREAM_LOG(trace,
514:                      "ext_authz filter added header(s) to the request:", *decoder_callbacks_);
515:     for (const auto& [key, value] : response->headers_to_set) {
516:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
517:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
518:       switch (check_result) {
519:       case CheckResult::OK:
520:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
521:         request_headers_->setCopy(Http::LowerCaseString(key), value);
522:         break;
523:       case CheckResult::IGNORE:
524:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to set '{}':'{}'.", *decoder_callbacks_,
525:                          key, value);
526:         break;
527:       case CheckResult::FAIL:
528:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to set '{}':'{}'.", *decoder_callbacks_,
529:                          key, value);
530:         rejectResponse();
531:         return;
532:       }
533:     }
534:     for (const auto& [key, value] : response->headers_to_add) {
535:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
536:           Filters::Common::MutationRules::CheckOperation::SET, key, value);
537:       switch (check_result) {
538:       case CheckResult::OK:
539:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
540:         request_headers_->addCopy(Http::LowerCaseString(key), value);
541:         break;
542:       case CheckResult::IGNORE:
543:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to add '{}':'{}'.", *decoder_callbacks_,
544:                          key, value);
545:         break;
546:       case CheckResult::FAIL:
547:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to add '{}':'{}'.", *decoder_callbacks_,
548:                          key, value);
549:         rejectResponse();
550:         return;
551:       }
552:     }
553:     for (const auto& [key, value] : response->headers_to_append) {
554:       CheckResult check_result = validateAndCheckDecoderHeaderMutation(
555:           Filters::Common::MutationRules::CheckOperation::APPEND, key, value);
556:       switch (check_result) {
557:       case CheckResult::OK: {
558:         ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
559:         Http::LowerCaseString lowercase_key(key);
560:         const auto header_to_modify = request_headers_->get(lowercase_key);
561:         // TODO(dio): Add a flag to allow appending non-existent headers, without setting it
562:         // first (via `headers_to_add`). For example, given:
563:         // 1. Original headers {"original": "true"}
564:         // 2. Response headers from the authorization servers {{"append": "1"}, {"append":
565:         // "2"}}
566:         //
567:         // Currently it is not possible to add {{"append": "1"}, {"append": "2"}} (the
568:         // intended combined headers: {{"original": "true"}, {"append": "1"}, {"append":
569:         // "2"}}) to the request to upstream server by only sets `headers_to_append`.
570:         if (!header_to_modify.empty()) {
571:           ENVOY_STREAM_LOG(trace, "'{}':'{}'", *decoder_callbacks_, key, value);
572:           // The current behavior of appending is by combining entries with the same key,
573:           // into one entry. The value of that combined entry is separated by ",".
574:           // TODO(dio): Consider to use addCopy instead.
575:           request_headers_->appendCopy(lowercase_key, value);
576:         }
577:         break;
578:       }
579:       case CheckResult::IGNORE:
580:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header to append '{}':'{}'.", *decoder_callbacks_,
581:                          key, value);
582:         break;
583:       case CheckResult::FAIL:
584:         ENVOY_STREAM_LOG(trace, "Rejecting invalid header to append '{}':'{}'.",
585:                          *decoder_callbacks_, key, value);
586:         rejectResponse();
587:         return;
588:       }
589:     }
590: 
591:     ENVOY_STREAM_LOG(trace,
592:                      "ext_authz filter removed header(s) from the request:", *decoder_callbacks_);
593:     for (const auto& key : response->headers_to_remove) {
594:       // If the response contains an invalid header to remove, it's the same as trying to remove a
595:       // header that doesn't exist, so just ignore it.
596:       if (config_->validateMutations() && !Http::HeaderUtility::headerNameIsValid(key)) {
597:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
598:         continue;
599:       }
600:       // We don't allow removing any :-prefixed headers, nor Host, as removing them would make the
601:       // request malformed. checkDecoderHeaderMutation also performs this check, however, so only
602:       // perform this check explicitly if decoder header mutation rules is empty.
603:       if (!config_->hasDecoderHeaderMutationRules() &&
604:           !Http::HeaderUtility::isRemovableHeader(key)) {
605:         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
606:         continue;
607:       }
608:       // Check header mutation is valid according to configured decoder header mutation rules.
609:       Http::LowerCaseString lowercase_key(key);
610:       switch (config_->checkDecoderHeaderMutation(CheckOperation::REMOVE, lowercase_key,
611:                                                   EMPTY_STRING)) {
612:       case CheckResult::OK:
613:         ENVOY_STREAM_LOG(trace, "'{}'", *decoder_callbacks_, key);
614:         request_headers_->remove(lowercase_key);
615:         break;
616:       case CheckResult::IGNORE:
617:         ENVOY_STREAM_LOG(trace, "Ignoring disallowed header removal '{}'.", *decoder_callbacks_,
618:                          key);
619:         break;
620:       case CheckResult::FAIL:
621:         ENVOY_STREAM_LOG(trace, "Rejecting disallowed header removal '{}'.", *decoder_callbacks_,
622:                          key);
623:         rejectResponse();
624:         return;
625:       }
626:     }
627: 
628:     if (!response->response_headers_to_add.empty()) {
629:       ENVOY_STREAM_LOG(trace, "ext_authz filter saving {} header(s) to add to the response:",
630:                        *decoder_callbacks_, response->response_headers_to_add.size());
631:       for (const auto& [key, value] : response->response_headers_to_add) {
632:         if (config_->validateMutations() && (!Http::HeaderUtility::headerNameIsValid(key) ||
633:                                              !Http::HeaderUtility::headerValueIsValid(value))) {
634:           ENVOY_STREAM_LOG(trace, "Rejected invalid header '{}':'{}'.", *decoder_callbacks_, key,
635:                            value);
636:           rejectResponse();
637:           return;
638:         }
639:       }
640:       response_headers_to_add_ = Http::HeaderVector{response->response_headers_to_add.begin(),
641:                                                     response->response_headers_to_add.end()};
642:     }
