840: void Filter::rejectResponse() {
841:   const Http::Code status = Http::Code::InternalServerError;
842:   ENVOY_STREAM_LOG(trace, "ext_authz filter invalidated the response. Response status code: {}",
843:                    *decoder_callbacks_, enumToInt(status));
844:   if (cluster_) {
845:     config_->incCounter(cluster_->statsScope(), config_->ext_authz_invalid_);
846:   }
847:   stats_.invalid_.inc();
848:   decoder_callbacks_->streamInfo().setResponseFlag(
849:       StreamInfo::CoreResponseFlag::UnauthorizedExternalService);
850:   decoder_callbacks_->sendLocalReply(
851:       status, EMPTY_STRING, nullptr, absl::nullopt,
852:       Filters::Common::ExtAuthz::ResponseCodeDetails::get().AuthzInvalid);
853: }
