132: bool HeaderUtility::headerNameIsValid(absl::string_view header_key) {
133:   if (!header_key.empty() && header_key[0] == ':') {
134: #ifdef ENVOY_NGHTTP2
135:     if (!Runtime::runtimeFeatureEnabled(
136:             "envoy.reloadable_features.sanitize_http2_headers_without_nghttp2")) {
137:       // For HTTP/2 pseudo header, use the HTTP/2 semantics for checking validity
138:       return nghttp2_check_header_name(reinterpret_cast<const uint8_t*>(header_key.data()),
139:                                        header_key.size()) != 0;
140:     }
141: #endif
142:     header_key.remove_prefix(1);
143:     if (header_key.empty()) {
144:       return false;
145:     }
146:   }
147:   // For all other header use HTTP/1 semantics. The only difference from HTTP/2 is that
148:   // uppercase characters are allowed. This allows HTTP filters to add header with mixed
149:   // case names. The HTTP/1 codec will send as is, as uppercase characters are allowed.
150:   // However the HTTP/2 codec will NOT convert these to lowercase when serializing the
151:   // header map, thus producing an invalid request.
152:   // TODO(yanavlasov): make validation in HTTP/2 case stricter.
153:   bool is_valid = true;
154:   for (auto iter = header_key.begin(); iter != header_key.end() && is_valid; ++iter) {
155:     is_valid &= testCharInTable(kGenericHeaderNameCharTable, *iter);
156:   }
157:   return is_valid;
158: }
