365: void HeaderUtility::stripTrailingHostDot(RequestHeaderMap& headers) {
366:   auto host = headers.getHostValue();
367:   // If the host ends in a period, remove it.
368:   auto dot_index = host.rfind('.');
369:   if (dot_index == std::string::npos) {
370:     return;
371:   } else if (dot_index == (host.size() - 1)) {
372:     host.remove_suffix(1);
373:     headers.setHost(host);
374:     return;
375:   }
376:   // If the dot is just before a colon, it must be preceding the port number.
377:   // IPv6 addresses may contain colons or dots, but the dot will never directly
378:   // precede the colon, so this check should be sufficient to detect a trailing port number.
379:   if (host[dot_index + 1] == ':') {
380:     headers.setHost(absl::StrCat(host.substr(0, dot_index), host.substr(dot_index + 1)));
381:   }
382: }
