443: constexpr bool isInvalidToken(unsigned char c) {
444:   if (c == '!' || c == '|' || c == '~' || c == '*' || c == '+' || c == '-' || c == '.' ||
445:       // #, $, %, &, '
446:       (c >= '#' && c <= '\'') ||
447:       // [0-9]
448:       (c >= '0' && c <= '9') ||
449:       // [A-Z]
450:       (c >= 'A' && c <= 'Z') ||
451:       // ^, _, `, [a-z]
452:       (c >= '^' && c <= 'z')) {
453:     return false;
454:   }
455:   return true;
456: }
