458: absl::optional<std::reference_wrapper<const absl::string_view>>
459: HeaderUtility::requestHeadersValid(const RequestHeaderMap& headers) {
460:   // Make sure the host is valid.
461:   if (headers.Host() && !HeaderUtility::authorityIsValid(headers.Host()->value().getStringView())) {
462:     return SharedResponseCodeDetails::get().InvalidAuthority;
463:   }
464:   if (headers.Method()) {
465:     absl::string_view method = headers.Method()->value().getStringView();
466:     if (method.empty() || std::any_of(method.begin(), method.end(), isInvalidToken)) {
467:       return SharedResponseCodeDetails::get().InvalidMethod;
468:     }
469:   }
470:   if (headers.Scheme() && absl::StrContains(headers.Scheme()->value().getStringView(), ",")) {
471:     return SharedResponseCodeDetails::get().InvalidScheme;
472:   }
473:   return absl::nullopt;
474: }
