476: bool HeaderUtility::shouldCloseConnection(Http::Protocol protocol,
477:                                           const RequestOrResponseHeaderMap& headers) {
478:   // HTTP/1.0 defaults to single-use connections. Make sure the connection will be closed unless
479:   // Keep-Alive is present.
480:   if (protocol == Protocol::Http10 &&
481:       (!headers.Connection() ||
482:        !Envoy::StringUtil::caseFindToken(headers.Connection()->value().getStringView(), ",",
483:                                          Http::Headers::get().ConnectionValues.KeepAlive))) {
484:     return true;
485:   }
486: 
487:   if (protocol == Protocol::Http11 && headers.Connection() &&
488:       Envoy::StringUtil::caseFindToken(headers.Connection()->value().getStringView(), ",",
489:                                        Http::Headers::get().ConnectionValues.Close)) {
490:     return true;
491:   }
492: 
493:   // Note: Proxy-Connection is not a standard header, but is supported here
494:   // since it is supported by http-parser the underlying parser for http
495:   // requests.
496:   if (protocol < Protocol::Http2 && headers.ProxyConnection() &&
497:       Envoy::StringUtil::caseFindToken(headers.ProxyConnection()->value().getStringView(), ",",
498:                                        Http::Headers::get().ConnectionValues.Close)) {
499:     return true;
500:   }
501:   return false;
502: }
